import torch
from torchvision import models
from torchvision import transforms
from PIL import Image
import os
import requests
from tqdm import tqdm

# Define a function to download model checkpoints from URLs
def download_model(url, path):
    response = requests.get(url)
    with open(path, 'wb') as f:
        f.write(response.content)

# Download pre-trained models
model_urls = {
    'resnet18': 'https://download.pytorch.org/models/resnet18-5c106cde.pth',
    'vgg16': 'https://download.pytorch.org/models/vgg16-397923e5.pth'
}

for model_name, url in model_urls.items():
    download_model(url, f'models/{model_name}.pth')

# Load pre-trained models
models = {
    'resnet18': models.resnet18(),
    'vgg16': models.vgg16()
}
pretrained_dict = torch.load('models/resnet18.pth')
for model_name in models:
    models[model_name].load_state_dict(pretrained_dict)

# Define a function to fine-tune the downloaded models
def fine_tune(model, device, loader):
    criterion = torch.nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam(model.parameters(), lr=0.001)
    
    for epoch in range(10):
        model.train()
        running_loss = 0.0
        for i, data in enumerate(loader):
            inputs, labels = data
            inputs, labels = inputs.to(device), labels.to(device)
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()
        
        print(f'Epoch {epoch+1}, Loss: {running_loss/(i+1)}')
    
    model.eval()

# Define a custom dataset class
class CustomDataset(torch.utils.data.Dataset):
    def __init__(self, data_dir, transform=None):
        self.data_dir = data_dir
        self.transform = transform
        self.images = os.listdir(data_dir)
    
    def __len__(self):
        return len(self.images)
    
    def __getitem__(self, index):
        image_path = os.path.join(self.data_dir, self.images[index])
        image = Image.open(image_path)
        if self.transform:
            image = self.transform(image)
        return image

# Load custom dataset
data_dir = 'path_to_your_dataset'
transform = transforms.Compose([transforms.Resize(256), transforms.CenterCrop(224), transforms.ToTensor()])
dataset = CustomDataset(data_dir, transform=transform)

# Fine-tune the downloaded models on the custom dataset
device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
loader = torch.utils.data.DataLoader(dataset, batch_size=32, shuffle=True)
for model_name in models:
    fine_tune(models[model_name], device, loader)